mapper.select:
/*
	 SQL ID : UsrDeptCdDAO.select
	 설  명 : 학과(부서) 정보 조회
*/

	AND A.DEPT_ID = #{deptId}

		AND ORG_ID = #{orgId}

/* SQL ID : UsrDeptCdDAO.list 설 명 : 학과(부서) 목록 조회 */
AND A.ORG_ID = #{orgId}
AND ( LOWER(A.DEPT_ID) LIKE '%' || LOWER(#{searchValue})|| '%' OR LOWER(A.DEPTNM) LIKE '%'|| LOWER(#{searchValue}) || '%' OR LOWER(A.DEPT_ENNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
ORDER BY A.DEPTNM DESC

/*
	SQL ID : count
	설  명 : 부서 정보의 전체 카운트
*/
SELECT COUNT(*) FROM (


		AND A.ORG_ID = #{orgId}


		AND (
				LOWER(A.DEPT_ID) LIKE CONCAT('%', LOWER(#{searchValue}), '%')
			 OR LOWER(A.DEPTNM) LIKE CONCAT('%', LOWER(#{searchValue}), '%')
		)

	 ORDER BY A.DEPT_ID_ODR DESC
) T

/*
	 SQL ID : UsrDeptCdDAO.listPageing
	 설  명 : 학과(부서) 목록 조회 페이징
*/



		AND A.ORG_ID = #{orgId}


		AND (
				  LOWER(A.DEPT_ID) LIKE CONCAT('%', LOWER(#{searchValue}), '%')
			 OR LOWER(A.DEPTNM) LIKE CONCAT('%', LOWER(#{searchValue}), '%')
		)

ORDER BY A.DEPT_ID_ODR DESC

mapper.insert:
	/*
		 SQL ID : UsrDeptCdDAO.insert
		 설  명 : 학과(부서) 등록
 	*/
	INSERT INTO TB_HOME_USER_DEPT_ID (
		  DEPT_ID
		, ORG_ID
		, DEPTNM
		, DEPT_NM_EN
		, PAR_DEPT_ID
		, RGTR_ID
		, FRST_INQ_DTTM
	) VALUES (
		  #{deptId}
		, #{orgId}
		, #{deptNm}
		, #{deptEnnm}
		, #{upDeptId}
		, #{rgtrId}
		, FN_DTTM()
	)

mapper.update:
/*
	 SQL ID : UsrDeptCdDAO.update
	 설  명 : 학과(부서) 수정
*/
UPDATE TB_HOME_USER_DEPT_ID
      SET DEPT_ID = #{deptId}
         , DEPTNM = #{deptNm}

         , DEPT_NM_EN = #{deptEnnm}

         , PAR_DEPT_ID = #{upDeptId}
         , MDFR_ID = #{mdfrId}
         , MOD_DTTM = FN_DTTM()
 WHERE DEPT_ID = #{deptId}

mapper.delete:
/*
	 SQL ID : UsrDeptCdDAO.delete
	 설  명 : 학과(부서) 삭제
*/
DELETE FROM TB_HOME_USER_DEPT_ID
 WHERE DEPT_ID = #{deptId}

mapper.update:
/*
	 SQL ID : UsrDeptCdDAO.updateUseYn
	 설  명 : 학과(부서) > 사용여부 변경
*/

	UPDATE TB_HOME_USER_DEPT_ID
	   SET USEYN  = #{useYn}
	     , MDFR_ID  = #{mdfrId}
	     , MOD_DTTM  = FN_DTTM()
	 WHERE DEPT_ID = #{deptId}
